INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'What is the molecular formula of glucose?', 'C₆H₆O₁₂', 'C₆H₁₈O₁₂', 'C₆H₁₂O₁₈', 'C₆H₁₂O₆', 4, 'The molecular formula of glucose is C₆H₁₂O₆, representing six carbon, twelve hydrogen, and six oxygen atoms.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following is a main source of Vitamin C? I. Guava II. Egg', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Guava is a rich source of Vitamin C. Eggs do not contain significant amounts of Vitamin C. So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''substance – chemical formula'' is/are correctly matched? I. Washing soda – Na₂CO₃ II. Plaster of Paris – CaOCl₂', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Washing soda is Na₂CO₃ (correct). Plaster of Paris is CaSO₄·½H₂O, not CaOCl₂ (which is bleaching powder). So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following organisms belongs to the phylum Annelida? I. Scorpion II. Earthworm', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Earthworm belongs to phylum Annelida. Scorpion belongs to phylum Arthropoda (class Arachnida). So Only II is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'In August 1999, a High Powered Committee on Disaster Management was constituted under the Chairmanship of ______.', 'J.C. Pant', 'P.K. Sinha', 'A.K. Bhalla', 'D.S. Mishra', 1, 'The High Powered Committee on Disaster Management in August 1999 was chaired by J.C. Pant, which led to the Disaster Management Act.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'The Central Soil and Water Conservation Research and Training Institute is located in ______.', 'Chandigarh', 'Dehradun', 'Hyderabad', 'Bengaluru', 2, 'The Central Soil and Water Conservation Research and Training Institute is located in Dehradun, Uttarakhand.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is a natural hazard? I. Landslide II. Building collapse', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Landslide is a natural hazard caused by geological factors. Building collapse is a man-made hazard. So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'As per the final report of the High Powered Committee on Disaster management, which of the following is/are categorised under Geologically related Hazards? I. Droughts II. Earthquakes', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Earthquakes are geologically related hazards. Droughts are climatological hazards (water-related). So Only II is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'In India, about ______ percent of the landmass is prone to earthquakes of various intensities.', '40', '50', '60', '70', 3, 'About 60% of India''s landmass is prone to earthquakes of various intensities, with Zone V being the most active.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct in the context of major disasters in India since 1970? I. An earthquake of magnitude 6.6 killed more than 700 people in Uttarkashi on 20th October 1991. II. Approximately 8000 people died and there was a heavy loss to infrastructure in Latur on 30th September 1993.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Uttarkashi earthquake (1991, 6.6 magnitude) killed over 700 people, and Latur earthquake (1993) killed approximately 8000 people.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'The lowest region of atmosphere in which the human beings along with other organisms live is called ______.', 'Troposphere', 'Stratosphere', 'Thermosphere', 'Exosphere', 1, 'The troposphere is the lowest layer of the atmosphere where humans and most organisms live, extending from ground level up to about 12-15 km.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', '______ refers to the increase in concentration of toxins at successive trophic levels.', 'Biomagnification', 'Eutrophication', 'Detoxification', 'Bioremediation', 1, 'Biomagnification (or bioamplification) is the increase in concentration of toxins (like DDT, mercury) at successive trophic levels in a food chain.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is a greenhouse gas? I. Sulphur dioxide II. Carbon dioxide', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Carbon dioxide is a greenhouse gas. Sulphur dioxide is a pollutant but not a major greenhouse gas; it contributes to acid rain.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is/are correct regarding the consequence of deforestation? I. Soil erosion II. Desertification', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both soil erosion and desertification are major consequences of deforestation, as trees bind the soil and maintain the water cycle.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is/are correct regarding the greenhouse effect? I. It is a naturally occurring phenomenon responsible for heating of Earth''s surface and atmosphere. II. It is caused due to excessive accumulation of biodegradable substance in water system.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'The greenhouse effect is a natural phenomenon that warms the Earth. Statement II is incorrect; it describes eutrophication, not the greenhouse effect.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is an advantage of CNG over petrol or diesel? I. Pipelines can be laid to supply CNG. II. CNG cannot be siphoned off like petrol or diesel.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'CNG cannot be siphoned off like petrol/diesel, making it more secure. Pipelines are not an advantage unique to CNG. So Only II is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the ''3R'' principle? I. Reduce is the first and most important principle of the 3R. II. Recycling involves using the same item repeatedly for the same purpose.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Reduce is the most important principle (prevention first). Recycling involves processing waste into new products, not using the same item repeatedly (which is reuse). So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'The outermost range of the Himalayas is called the ______.', 'Himadri', 'Shiwaliks', 'Himachal', 'Purvachal', 2, 'The outermost (southernmost) range of the Himalayas is the Shiwaliks (Siwalik Hills), also known as the Outer Himalayas.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Godavari river? I. It rises from the slopes of the Western Ghats in the Nasik district of Maharashtra. II. It drains into the Arabian Sea.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Godavari rises in Nasik, Maharashtra (Western Ghats). It drains into the Bay of Bengal, not the Arabian Sea. So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding alluvial soil? I. Old alluvial soil is called Khadar and new alluvial is called Bangar. II. Khadar is more fertile than the bangar.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Statement I is reversed: Khadar is new alluvial soil, Bangar is old alluvial soil. Khadar is more fertile than Bangar. So Only II is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the northern plain of India? I. It has been formed by the interplay of the Indus, the Ganga and the Brahmaputra along with their tributaries. II. The plain is about 2400 km long.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: the northern plain is formed by the Indus, Ganga, Brahmaputra and their tributaries, and is approximately 2400 km long.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the climate of India? I. The cold weather season begins from mid November in northern India and stays till February. II. December and January are the coldest months in the northern part of India.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: cold weather season in north India runs from mid-November to February, with December and January being the coldest months.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''national park - state'' is/are correctly matched? I. Periyar Tiger Reserve - Kerala II. Manas Tiger Reserve - Odisha', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Periyar Tiger Reserve is in Kerala (correct). Manas Tiger Reserve is in Assam, not Odisha. So Only I is correct.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Indus river system? I. The river Indus rises in Tibet, near Lake Mansarovar. II. The total length of the Indus is 3900 km.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Indus rises in Tibet near Lake Mansarovar and has a total length of about 3900 km.', 'medium'),
('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Fundamental Duties of the citizens have also been enumerated in the Indian constitution by the ______.', '32nd Amendment', '34th Amendment', '42nd Amendment', '44th Amendment', 3, 'Fundamental Duties were added to the Indian Constitution by the 42nd Amendment Act, 1976, on the recommendation of the Swaran Singh Committee.', 'medium')
